// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./PortfolioRegistry.sol";
import "./RelationshipRegistry.sol";

contract OpportunityAlert {
    RelationshipRegistry public relationshipRegistry;
    PortfolioRegistry public portfolioRegistry;

    struct Alert {
        address investor;
        bytes32 relationshipId;
        string entityA;
        string entityB;
        string relationshipType;
        string opportunityType;
        uint256 timestamp;
    }

    Alert[] private alerts;
    mapping(address => uint256[]) public investorAlerts;
    mapping(bytes32 => mapping(address => bool)) public emittedForInvestor;

    event CollaborationOpportunityFound(
        address indexed investor,
        bytes32 indexed relationshipId,
        string entityA,
        string entityB,
        string relationshipType,
        string opportunityType,
        uint256 alertId
    );

    constructor(address relationshipRegistryAddress, address portfolioRegistryAddress) {
        require(relationshipRegistryAddress != address(0), "Relationship registry required");
        require(portfolioRegistryAddress != address(0), "Portfolio registry required");

        relationshipRegistry = RelationshipRegistry(relationshipRegistryAddress);
        portfolioRegistry = PortfolioRegistry(portfolioRegistryAddress);
    }

    function checkForOpportunity(
        address investor,
        string memory entityA,
        string memory entityB,
        string memory relationshipType
    ) external returns (bool) {
        require(investor != address(0), "Investor required");
        require(
            relationshipRegistry.relationshipExists(entityA, entityB, relationshipType),
            "Relationship missing"
        );

        bytes32 relationshipId = relationshipRegistry.relationshipIdFor(entityA, entityB, relationshipType);
        if (emittedForInvestor[relationshipId][investor]) {
            return false;
        }

        bool entityAInPortfolio = portfolioRegistry.isEntityInPortfolio(investor, entityA);
        bool entityBInPortfolio = portfolioRegistry.isEntityInPortfolio(investor, entityB);

        if (!(entityAInPortfolio && entityBInPortfolio)) {
            return false;
        }

        uint256 alertId = alerts.length;
        alerts.push(
            Alert({
                investor: investor,
                relationshipId: relationshipId,
                entityA: entityA,
                entityB: entityB,
                relationshipType: relationshipType,
                opportunityType: "PORTFOLIO_CROSSOVER",
                timestamp: block.timestamp
            })
        );

        emittedForInvestor[relationshipId][investor] = true;
        investorAlerts[investor].push(alertId);

        emit CollaborationOpportunityFound(
            investor,
            relationshipId,
            entityA,
            entityB,
            relationshipType,
            "PORTFOLIO_CROSSOVER",
            alertId
        );

        return true;
    }

    function getAlertCount() external view returns (uint256) {
        return alerts.length;
    }

    function getAlert(uint256 alertId) external view returns (Alert memory) {
        require(alertId < alerts.length, "Alert missing");
        return alerts[alertId];
    }

    function getInvestorAlerts(address investor) external view returns (uint256[] memory) {
        return investorAlerts[investor];
    }
}

contracts/PortfolioRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract PortfolioRegistry {
    struct Portfolio {
        address investor;
        string[] companies;
        string[] founders;
    }

    mapping(address => Portfolio) private portfolios;

    event PortfolioUpdated(address indexed investor, uint256 companyCount, uint256 founderCount);

    function registerPortfolio(string[] memory companies, string[] memory founders) external {
        portfolios[msg.sender] = Portfolio({
            investor: msg.sender,
            companies: companies,
            founders: founders
        });

        emit PortfolioUpdated(msg.sender, companies.length, founders.length);
    }

    function getPortfolio(address investor) external view returns (Portfolio memory) {
        return portfolios[investor];
    }

    function getCompanies(address investor) external view returns (string[] memory) {
        return portfolios[investor].companies;
    }

    function getFounders(address investor) external view returns (string[] memory) {
        return portfolios[investor].founders;
    }

    function isEntityInPortfolio(address investor, string memory entity) external view returns (bool) {
        Portfolio storage portfolio = portfolios[investor];
        return _isInArray(entity, portfolio.companies) || _isInArray(entity, portfolio.founders);
    }

    function _isInArray(string memory target, string[] storage arr) internal view returns (bool) {
        bytes32 targetHash = keccak256(bytes(target));
        for (uint256 i = 0; i < arr.length; i++) {
            if (keccak256(bytes(arr[i])) == targetHash) {
                return true;
            }
        }
        return false;
    }
}

contracts/RelationshipRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";

contract RelationshipRegistry is Ownable {
    struct Relationship {
        string entityA;
        string entityB;
        string relationshipType;
        uint256 timestamp;
        bool verified;
    }

    mapping(bytes32 => Relationship) public relationships;
    address public attestationOracle;

    event AttestationOracleUpdated(address indexed previousOracle, address indexed nextOracle);
    event RelationshipRecorded(
        bytes32 indexed relationshipId,
        string entityA,
        string entityB,
        string relationshipType,
        uint256 timestamp
    );

    modifier onlyOracle() {
        require(msg.sender == attestationOracle, "Not authorized");
        _;
    }

    constructor(address initialOwner, address initialOracle) Ownable(initialOwner) {
        require(initialOracle != address(0), "Oracle required");
        attestationOracle = initialOracle;
        emit AttestationOracleUpdated(address(0), initialOracle);
    }

    function setAttestationOracle(address newOracle) external onlyOwner {
        require(newOracle != address(0), "Oracle required");

        address previousOracle = attestationOracle;
        attestationOracle = newOracle;
        emit AttestationOracleUpdated(previousOracle, newOracle);
    }

    function relationshipIdFor(
        string memory entityA,
        string memory entityB,
        string memory relationshipType
    ) public pure returns (bytes32) {
        return keccak256(abi.encode(entityA, entityB, relationshipType));
    }

    function recordRelationship(
        string memory entityA,
        string memory entityB,
        string memory relationshipType
    ) external onlyOracle returns (bytes32 relationshipId) {
        relationshipId = relationshipIdFor(entityA, entityB, relationshipType);

        relationships[relationshipId] = Relationship({
            entityA: entityA,
            entityB: entityB,
            relationshipType: relationshipType,
            timestamp: block.timestamp,
            verified: true
        });

        emit RelationshipRecorded(relationshipId, entityA, entityB, relationshipType, block.timestamp);
    }

    function relationshipExists(
        string memory entityA,
        string memory entityB,
        string memory relationshipType
    ) public view returns (bool) {
        bytes32 relationshipId = relationshipIdFor(entityA, entityB, relationshipType);
        return relationships[relationshipId].verified;
    }
}

